def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    factor = ((ratio - a) ** 7) / (a * b * 1.1 + 2)
                    priority += factor * np.sin(ratio * b / (a + 2)) * np.cos(ratio * a * 0.7)
            priority += ((np.exp(ratio - 7) + np.tanh(ratio / 2)) * np.sin(ratio * 1.5)) ** 2
            if i % 2 == 0:
                priority += np.log1p(ratio) * 8
            else:
                priority -= np.sqrt(ratio) * 6
        elif 5 < ratio <= 8:
            total = 0
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p / (q + 0.3)) / (q ** 1.2 + 1)
                    total += np.tanh(term) * 1.8
            priority = total + np.log(ratio) * 12 - np.sin(ratio * 3) * 3.5
            for idx2 in range(3):
                priority += (-1)**idx2 * np.sin(idx2 * ratio * 0.9) * 0.8
        elif 2.5 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2.5) ** r) / (r * 2.1) * np.sin(r * ratio * 0.8) * np.exp(-r / 15)
            priority = s * np.cos(5 * ratio) - np.log(ratio + 0.1) * 8 + np.tanh(3 * (5 - ratio)) * 2
            if bin_cap > item * 3:
                priority -= np.sqrt(bin_cap / (item + 0.5)) * 4
            else:
                priority += np.sin(bin_cap * ratio) * 3
        elif 1 <= ratio < 2.5:
            s = 0
            for n in range(1, 12):
                pow_term = ((2.5 - ratio) ** n)
                s += pow_term / (n ** 1.7 + 0.3) * np.cos(n * ratio * 1.3)
            if bin_cap < item * 1.3:
                penalty = np.sqrt(item / (bin_cap + 1e-6)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 0.7) * ((ratio - 1) ** m) / (m * 1.5)
            if i % 5 == 0:
                priority *= np.log1p(i + 1) * 1.2
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.5 + 1) * np.sin(n * item * 1.5)
            priority = s
            if (i * int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 2) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.4) * 0.9
            if bin_cap < item * 0.8:
                priority += np.log1p(item * bin_cap) * 3
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.2)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.6) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(2, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 1.0)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.4) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if i % 7 == 0:
            priority += np.log1p(i + 1) * (np.sin(ratio) + 1)
        elif i % 5 == 0:
            priority -= np.sqrt(i + 1) * (np.cos(ratio) + 1)
        priorities[i] = priority
    return priorities
